from math import factorial
def a(n: int) -> int:
    if n == 0: return 0
    t = factorial(n)
    f = t
    for m in range(1, n):
        t = n * t // m
        f += t
    return f
print([a(n) for n in range(1, 20)])  # _Peter Luschny_, Mar 09 2026

